import { Component, OnInit, DestroyRef } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ReactiveFormsModule, FormBuilder, FormGroup, Validators } from '@angular/forms';
import { Router } from '@angular/router';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { AuthService } from '../../core/services/auth.service';
import { UiService } from '../../core/services/ui.service';

@Component({
  selector: 'app-auth',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule],
  templateUrl: './auth.component.html',
  styleUrls: ['./auth.component.scss']
})
export class AuthComponent implements OnInit {
  loginForm!: FormGroup;
  registerForm!: FormGroup;
  isLogin = true;
  loading = false;
  error = '';

  constructor(
    private fb: FormBuilder,
    private authService: AuthService,
    private router: Router,
    private destroyRef: DestroyRef
  ) {
    this.initializeForms();
  }

  ngOnInit(): void {
    if (this.authService.isAuthenticated()) {
      this.router.navigate(['/dashboard']);
    }
  }

  private initializeForms(): void {
    this.loginForm = this.fb.group({
      email: ['demo@metaiq.dev', [Validators.required, Validators.email]],
      password: ['Demo@1234', [Validators.required, Validators.minLength(6)]]
    });

    this.registerForm = this.fb.group({
      email: ['', [Validators.required, Validators.email]],
      password: ['', [Validators.required, Validators.minLength(6)]],
      confirmPassword: ['', [Validators.required]]
    });
  }

  toggleMode(): void {
    this.isLogin = !this.isLogin;
    this.error = '';
  }

  onSubmit(): void {
    const form = this.isLogin ? this.loginForm : this.registerForm;
    if (form.invalid) {
      this.error = 'Por favor, preencha todos os campos corretamente';
      return;
    }

    this.loading = true;
    this.error = '';

    if (this.isLogin) {
      this.authService
        .login(form.value)
        .pipe(takeUntilDestroyed(this.destroyRef))
        .subscribe({
          next: () => {
            this.router.navigate(['/dashboard']);
          },
          error: (err) => {
            this.loading = false;
            this.error = err?.message || 'Erro ao fazer login. Verifique suas credenciais.';
          }
        });
    } else {
      this.authService
        .register(form.value)
        .pipe(takeUntilDestroyed(this.destroyRef))
        .subscribe({
          next: () => {
            this.isLogin = true;
            this.loginForm.patchValue({
              email: form.value.email,
              password: form.value.password
            });
            this.error =
              'Conta criada com sucesso! Faça login para continuar.';
            setTimeout(() => (this.error = ''), 3000);
          },
          error: (err) => {
            this.loading = false;
            this.error =
              err?.message ||
              'Erro ao criar conta. Tente novamente.';
          }
        });
    }
  }

  getFieldError(fieldName: string): string {
    const form = this.isLogin ? this.loginForm : this.registerForm;
    const field = form.get(fieldName);
    if (!field || !field.errors || !field.touched) return '';

    if (field.errors['required']) return 'Este campo é obrigatório';
    if (field.errors['email']) return 'Email inválido';
    if (field.errors['minlength'])
      return `Mínimo ${field.errors['minlength'].requiredLength} caracteres`;

    return '';
  }
}
<div class="auth-container">
  <div class="auth-card">
    <div class="auth-header">
      <h1 class="logo">meta<span>IQ</span></h1>
      <p class="subtitle">{{ isLogin ? 'Faça login na sua conta' : 'Crie uma nova conta' }}</p>
    </div>

    <form [formGroup]="isLogin ? loginForm : registerForm" (ngSubmit)="onSubmit()" class="auth-form">
      <!-- Email Field -->
      <div class="form-group">
        <label for="email" class="form-label">Email</label>
        <input
          type="email"
          id="email"
          formControlName="email"
          class="form-input"
          [class.error]="isLogin ? loginForm.get('email')?.touched && loginForm.get('email')?.invalid : registerForm.get('email')?.touched && registerForm.get('email')?.invalid"
          placeholder="você@exemplo.com"
        />
        <span class="error-message" *ngIf="getFieldError('email')">{{ getFieldError('email') }}</span>
      </div>

      <!-- Password Field -->
      <div class="form-group">
        <label for="password" class="form-label">Senha</label>
        <input
          type="password"
          id="password"
          formControlName="password"
          class="form-input"
          [class.error]="isLogin ? loginForm.get('password')?.touched && loginForm.get('password')?.invalid : registerForm.get('password')?.touched && registerForm.get('password')?.invalid"
          placeholder="••••••••"
        />
        <span class="error-message" *ngIf="getFieldError('password')">{{ getFieldError('password') }}</span>
      </div>

      <!-- Confirm Password Field (Register only) -->
      <div class="form-group" *ngIf="!isLogin">
        <label for="confirmPassword" class="form-label">Confirme a Senha</label>
        <input
          type="password"
          id="confirmPassword"
          formControlName="confirmPassword"
          class="form-input"
          placeholder="••••••••"
        />
      </div>

      <!-- Global Error -->
      <div class="auth-error" *ngIf="error && !error.includes('sucesso')">
        {{ error }}
      </div>

      <!-- Success Message -->
      <div class="auth-success" *ngIf="error && error.includes('sucesso')">
        {{ error }}
      </div>

      <!-- Submit Button -->
      <button type="submit" class="btn btn-primary" [disabled]="loading || (isLogin ? loginForm.invalid : registerForm.invalid)">
        <span *ngIf="!loading">{{ isLogin ? 'Entrar' : 'Criar Conta' }}</span>
        <span *ngIf="loading" class="spinner"></span>
      </button>
    </form>

    <!-- Demo Credentials Hint -->
    <div class="demo-hint" *ngIf="isLogin">
      <p class="hint-text">Demo: demo@metaiq.dev / Demo@1234</p>
    </div>

    <!-- Toggle Mode -->
    <div class="auth-toggle">
      <span>{{ isLogin ? 'Não tem conta?' : 'Já tem conta?' }}</span>
      <button type="button" (click)="toggleMode()" class="toggle-link">
        {{ isLogin ? 'Registre-se' : 'Faça login' }}
      </button>
    </div>
  </div>
</div>
